1	{{ $src := .Get "src" }}
2	{{ $cols := .Get "cols" | default "80" }}
3	{{ $rows := .Get "rows" | default "24" }}
4	{{ $id := printf "player-%s" ($src | urlize) }}
5	<div class="asciinema-container" style="margin: 1.5rem 0;">
6	  <div id="{{ $id }}"></div>
7	</div>
8	<script>
9	  (function() {
10	    // Load asciinema-player CSS/JS once
11	    if (!document.querySelector('link[href*="asciinema-player"]')) {
12	      var css = document.createElement('link');
13	      css.rel = 'stylesheet';
14	      css.href = 'https://unpkg.com/asciinema-player@3.7.1/dist/bundle/asciinema-player.css';
15	      document.head.appendChild(css);
16	      var js = document.createElement('script');
17	      js.src = 'https://unpkg.com/asciinema-player@3.7.1/dist/bundle/asciinema-player.min.js';
18	      js.onload = function() { initPlayer(); };
19	      document.head.appendChild(js);
20	    } else {
21	      // Already loaded — init immediately or wait for script
22	      if (window.AsciinemaPlayer) { initPlayer(); }
23	      else { setTimeout(initPlayer, 500); }
24	    }
25	    function initPlayer() {
26	      if (!window.AsciinemaPlayer) return;
27	      var el = document.getElementById('{{ $id }}');
28	      if (el && !el.hasChildNodes()) {
29	        AsciinemaPlayer.create('{{ site.BaseURL }}demos/{{ $src }}.cast', el, {
30	          cols: {{ $cols }},
31	          rows: {{ $rows }},
32	          theme: 'monokai',
33	          fit: 'width',
34	          autoPlay: true,
35	          speed: 1.5
36	        });
37	      }
38	    }
39	  })();
40	</script>
