}

.dark .ddx-maturity--stable {
  background: #064e3b;
  color: #6ee7b7;
}

.dark .ddx-maturity--beta {
  background: #451a03;
  color: #fcd34d;
}

.dark .ddx-maturity--planned {
  background: #1f2937;
  color: #9ca3af;
